class Solution:
    def islandPerimeter(self, grid):
        rows = len(grid)
        cols = len(grid[0])
        land = 0
        adjacent = 0
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 1:
                    land += 1
                    if r + 1 < rows and grid[r + 1][c] == 1:
                        adjacent += 1
                    if c + 1 < cols and grid[r][c + 1] == 1:
                        adjacent += 1
        return 4 * land - 2 * adjacent

